"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[892],{3976:e=>{e.exports=JSON.parse('{"functions":[{"name":"Destroy","desc":"Destroys the Species object instantly and sets `Opertable` to nil\\n\\n:::caution Recursive\\nCalling destroy on a `Ecosystem` object will cause **ALL** species objects binded to the ecosystem to also be destroyed.\\n:::\\n\\n### Example:\\n```lua\\n\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\n\\n-- Destroys the ecosystem object and all binded Species objects\\nNPCController:Destroy() \\n\\n```\\n\\n### Or:\\n\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\n\\n-- Destroys the ecosystem object and all binded Species objects and their instances\\nNPCController:Destroy(true) \\n\\n```","params":[{"name":"Nuke","desc":"If instances should be destroyed or dereferenced","lua_type":"Boolean"}],"returns":[{"desc":"","lua_type":"nil"}],"function_type":"method","source":{"line":839,"path":"src/init.luau"}},{"name":"AddStateFeature","desc":"Adds a new state with the given ID and binds the function to the ID\\n\\n:::info Reserved key\\nThe string `Stop` is reserved if you want to end the running thread. It is equivalent to calling `CurrentSpecies:Stop()`\\n:::\\n\\n:::danger Returns\\nEvery state function **MUST** return a valid state ID and a single string. *Note:* this does **NOT** mean you can only return 1 state per feature function you may have conditional statements that return different states to execute next.\\n:::\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\n\\n-- State Jump\\nNPCController:AddStateAndFeature(\\"Jump10Times\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\tlocal Count = 0\\n\\tlocal CurrentObjectHumanoid:Humanoid = CurrentSpecies.ObjectBinded.Humanoid\\n\\n\\twhile task.wait(0.1) do\\n\\t\\tif not CurrentObjectHumanoid.Jump then\\n\\t\\t\\tCurrentObjectHumanoid.Jump = true\\n\\t\\t\\tCount += 1\\n\\t\\tend\\n\\t\\tif Count >= 10 then\\n\\t\\t\\t-- Returns the next state to run\\n\\t\\t\\treturn \\"Wander\\"\\n\\t\\tend\\n\\tend\\nend)\\n\\n-- State Walk\\nNPCController:AddStateAndFeature(\\"Wander\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\tlocal CurrentObjectHumanoid:Humanoid = CurrentSpecies.ObjectBinded.Humanoid\\n\\tlocal HRP:BasePart = CurrentSpecies.ObjectBinded.HumanoidRootPart\\n\\tlocal Count = 10\\n\\n\\twhile task.wait(1) do\\n\\t\\tif Count >= 10 then\\n\\t\\t\\t-- Ends the running thread\\n\\t\\t\\treturn \\"Stop\\" -- reserved\\n\\t\\tend\\n\\n\\t\\t-- Move to a random position with a 50 stud box every second\\n\\t\\tCurrentObjectHumanoid:MoveTo(math.random(-50,50) + HRP.position.X, 0, math.random(-50, 50) + HRP.position.Z)\\n\\t\\tCount += 1\\n\\tend\\nend)\\n\\n```","params":[{"name":"State","desc":"The States ID","lua_type":"string"},{"name":"Feature","desc":"The function binded to the StateID","lua_type":"FunctionState"}],"returns":[],"function_type":"method","source":{"line":915,"path":"src/init.luau"}},{"name":"AddCustomProperty","desc":"Adds a new **Local property** to the template with a initial value if passed\\n\\n:::info Local\\nAll properties created in the `FunctionProperties` are **local** and are independent among every species created. They can only be edited at runtime by the `Species` class\\n:::\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\n\\n-- New local property with a initial value of 20\\nNPCController:AddCustomProperty(\\"LocalProperty\\", 20)\\n\\n-- New local property with a initial value of nil\\nNPCController:AddCustomProperty(\\"LocalProperty2\\")\\n\\n```","params":[{"name":"PropertyIndex","desc":"The index of the local property","lua_type":"string"},{"name":"InitialValue","desc":"The initial value","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":959,"path":"src/init.luau"}},{"name":"SetFunctionEnviorment","desc":"Adds a new **Global property** to the template with a initial value if passed\\n\\n:::info Global\\nAll properties created in the `FunctionEnviorment` are **global** and are shared among every species created. They can only be edited at runtime by the `Ecosystem` class\\n:::\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\n\\n-- New global property with a initial value of 20\\nNPCController:SetFunctionEnviorment(\\"GlobalProperty\\", 20)\\n\\n-- New global property with a initial value of nil\\nNPCController:SetFunctionEnviorment(\\"GlobalProperty2\\")\\n\\n```","params":[{"name":"PropertyIndex","desc":"The index of the Global property","lua_type":"string"},{"name":"InitialValue","desc":"The initial value","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":998,"path":"src/init.luau"}},{"name":"Freeze","desc":"\\"Freezes\\" the Ecosystem template allowing `Species` objects to be created from it\\n\\n:::tip Frozen\\nYou must freeze a `Ecosystem` object to create a `Species` object binded to it.\\n:::\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"WanderNPC\\")\\n\\n\\nlocal Specie1 = Ecosystem.NewSpecies(\\"WanderNPC\\") -- Error: Ecosystem must be Frozen\\n\\nprint(NPCController.Frozen) -- false\\n\\n-- Allows species to be created from \'WanderNPC\' class\\nNPCController:Freeze()\\n\\nprint(NPCController.Frozen) -- true\\n\\nlocal Specie1 = Ecosystem.NewSpecies(\\"WanderNPC\\") -- Returns: Species object from Ecosystem\\n\\n```","params":[],"returns":[],"function_type":"method","source":{"line":1039,"path":"src/init.luau"}},{"name":"UpdateFunctionEnviorment","desc":"Updates the **global** `Ecosystem` dictionary for all binded and future `Species` objects\\n\\n:::info Signal\\nRunning this function will cause the [EnviormentUpdate](#EnviormentUpdate) signal to broadcast\\n:::\\n\\n:::tip Global\\n`UpdateFunctionEnviorment` will update the **GLOBAL** dictionary ie: all species will receive the new data instantly\\n:::\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"WanderNPC\\")\\nNPCController:SetFunctionEnviorment(\\"MovementSpeed\\", 16) -- Default value of 16\\n\\n-- State Walk\\nNPCController:AddStateAndFeature(\\"Wander\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\tlocal CurrentObjectHumanoid:Humanoid = CurrentSpecies.ObjectBinded.Humanoid\\n\\tlocal HRP:BasePart = CurrentSpecies.ObjectBinded.HumanoidRootPart\\n\\n\\twhile task.wait(1) do\\n\\t\\t-- Updates the walkspeed to the global attribute value\\n\\t\\tCurrentObjectHumanoid.WalkSpeed = CurrentSpecies:GetEnviorment(\\"MovementSpeed\\")\\n\\n\\t\\t-- Move to a random position with a 50 stud box every second\\n\\t\\tCurrentObjectHumanoid:MoveTo(math.random(-50,50) + HRP.position.X, 0, math.random(-50, 50) + HRP.position.Z)\\n\\tend\\nend)\\n\\nlocal Species = Ecosystem.NewSpecies(\\"WanderNPC\\", NPCModel)\\n\\n-- Starts the runtime loop\\nSpecies:Start(\\"Wander\\")\\n\\nwhile task.wait(2) do\\n\\t-- Updates the enviorment attribute to a random number every 2 seconds\\n\\tNPCController:UpdateFunctionEnviorment(\\"MovementSpeed\\", math.random(10,40))\\nend\\n```","params":[{"name":"EnvVar","desc":"The index of the Global property","lua_type":"string"},{"name":"Data","desc":"The new data","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":1099,"path":"src/init.luau"}},{"name":"GetEnviorment","desc":"Returns the value of a enviorment variable with the given index\\n\\n:::info Read-Only\\nThe `Ecosystem` object **IS** able to write to `EnviormentVariables`, through  [`UpdateFunctionEnviorment`](#UpdateFunctionEnviorment).\\n:::\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"JumpingNPC\\")\\nNPCController:SetFunctionEnviorment(\\"GlobalVariable\\", 10) -- Initial value of 10\\n\\nprint(NPCController:GetEnviorment(\\"GlobalVariable\\")) -- 10\\nprint(NPCController:GetEnviorment(\\"GlobalVariable2\\")) -- nil\\nprint(NPCController:GetEnviorment()) -- The dictionary of enviorment properties\\n\\n```","params":[{"name":"EnvVar","desc":"The index of the enviorment variable","lua_type":"string?"}],"returns":[{"desc":"","lua_type":"any"}],"function_type":"method","source":{"line":1142,"path":"src/init.luau"}},{"name":"ForceState","desc":"Forces all `Species` objects binded to the `Ecosystem` to instantly switch to the next State\\n\\n### Example:\\n```lua\\nlocal NPCController = Ecosystem.NewEcosystem(\\"WanderNPC\\")\\n\\n-- State Walk\\nNPCController:AddStateAndFeature(\\"Wander\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\tlocal CurrentObjectHumanoid:Humanoid = CurrentSpecies.ObjectBinded.Humanoid\\n\\tlocal HRP:BasePart = CurrentSpecies.ObjectBinded.HumanoidRootPart\\n\\n\\tCurrentObjectHumanoid.WalkSpeed = 16\\n\\n\\twhile task.wait(1) do\\n\\t\\t-- Move to a random position with a 50 stud box every second\\n\\t\\tCurrentObjectHumanoid:MoveTo(math.random(-50,50) + HRP.position.X, 0, math.random(-50, 50) + HRP.position.Z)\\n\\tend\\nend)\\n\\n-- State Stun\\nNPCController:AddStateAndFeature(\\"Stun\\", function(CurrentSpecies: Ecosystem.Species, StateFrom: string): string\\n\\tlocal CurrentObjectHumanoid:Humanoid = CurrentSpecies.ObjectBinded.Humanoid\\n\\tCurrentObjectHumanoid.WalkSpeed = 0\\n\\ttask.wait(1)\\n\\treturn \\"Wander\\"\\nend)\\n\\n-- Creates 5 independent Specie objects binded to the WanderNPC Ecosystem controller\\nfor i = 1,5 do\\n\\tlocal C = NPCModel:Clone()\\n\\tlocal Species = Ecosystem.NewSpecies(\\"WanderNPC\\", C)\\n\\tC.parent = workspace\\n\\n\\tSpecies:Start(\\"Wander\\")\\nend\\n\\n-- Starts the runtime loop\\nSpecies:Start(\\"Wander\\")\\n\\nwhile task.wait(5) do\\n\\t-- Forces the stun state on all Species for 1 second\\n\\tNPCController:ForceState(\\"Stun\\")\\nend\\n```","params":[{"name":"StateID","desc":"A valid stateID","lua_type":"string"}],"returns":[],"function_type":"method","source":{"line":1214,"path":"src/init.luau"}}],"properties":[{"name":"EcosystemID","desc":"The identifier string that is passes in the `NewEcosystem` contstructor","lua_type":"string","readonly":true,"source":{"line":46,"path":"src/init.luau"}},{"name":"Frozen","desc":"A boolean that represents if the Ecosystem template is done being constructed and is ready to have Specie subclasses created from it.","lua_type":"Boolean","readonly":true,"source":{"line":53,"path":"src/init.luau"}},{"name":"Opertable","desc":"A boolean to check if the `Ecosystem` object has been destroyed or not. It is **permenetly** read-only","lua_type":"true?","readonly":true,"source":{"line":60,"path":"src/init.luau"}},{"name":"ClassName","desc":"The class of the object `Ecosystem`","lua_type":"string","readonly":true,"source":{"line":67,"path":"src/init.luau"}},{"name":"_States","desc":"The `States` template container","lua_type":"{ [string]: FunctionState }","private":true,"readonly":true,"source":{"line":75,"path":"src/init.luau"}},{"name":"_InternalProperties","desc":"The `Properties` template container __Local to the Species object__","lua_type":"{ [string]: any? }","private":true,"readonly":true,"source":{"line":83,"path":"src/init.luau"}},{"name":"_FunctionEnvVars","desc":"The `Enviorment` container __Global to the Ecosystem object__","lua_type":"{ [string]: any? }","private":true,"readonly":true,"source":{"line":91,"path":"src/init.luau"}},{"name":"_SpeciesBinded","desc":"A dictionary of all the species binded to the ecosystem __index is the speciesID__","lua_type":"{ [string]: Species }","private":true,"readonly":true,"source":{"line":99,"path":"src/init.luau"}},{"name":"EnviormentUpdate","desc":"A `tram` signal class that fires whenever a enviorment __Global__ variable is changed in the order of `(EnviormentVariableIndex:string, NewData:any, OldData:any)`","lua_type":"Tram<EnviormentVariableIndex:string, NewData:any, OldData:any)>","tags":["Signal"],"readonly":true,"source":{"line":107,"path":"src/init.luau"}}],"types":[{"name":"Ecosystem","desc":"The `Ecosystem` object is wrapped inside of the `SecuredClass` this provides protections such as proper read-only properties + more","lua_type":"SecuredClass <Ecosystem>","external_types":[{"name":"SecuredClass","url":"https://green-screen.github.io/SecureClasses/api/SecuredMetatable#WrappedMetatable"}],"source":{"line":30,"path":"src/init.luau"}},{"name":"FunctionState","desc":":::caution Return\\nA feature function **MUST** return a valid `StateID` string for the next state to run or **Stop** to stop close the current running thread\\n:::","lua_type":"(CurrentSpecies: Species, StateFrom: string?) -> string","source":{"line":39,"path":"src/init.luau"}}],"name":"Ecosystem","desc":"The main controller class, this object acts as the leader and template for all subclass [Species](/api/Species) and retains its control during runtime.","source":{"line":23,"path":"src/init.luau"}}')}}]);